sp_widget.client_script:
api.controller=function ($scope, $rootScope, spAriaFocusManager, $http, amb, $timeout, spUtil, $location, $window, nowAttachmentHandler, $log, spAriaUtil, spModal, $uibModal, spNavStateManager) {

	// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
	// Script Continued Below
	//------------------------------------------------------------------------------------------------------------------------
	var c = this;
	// STRY0076291
	//c.allowSubTask = false;
	// STRY0122687
	c.currentTab = null;
	$scope.countRelatedListsTabs = 0;
	// STRY0135701
	$scope.hasAdditionalLists = c.data.additionalLists && c.data.additionalLists.length>0;

	// DFCT0011062 - count the related lists including attachments that are being shown
	// STRY0135701
	if (!c.data.hideRelatedLists  || !c.data.hideDocuments || $scope.hasAdditionalLists) {
		// DFCT0011679 - Banner notification right side empty; add if not undefined
				// DFCT0011681 - Do not Count attachments, they were moved into a block with documents in the HTML
		if (c.data.f._related_lists != undefined) {
			$scope.countRelatedListsTabs = c.data.f._related_lists.filter(
			function(rl) {
				if (rl.showList && rl.table != "sys_attachment") {
					return rl;
				}
			}).length;

			// DFCT0011681 - Count attachments, they were moved into a block with documents in the HTML
			$scope.countAttachmentsTabs = c.data.f._related_lists.filter(
				function(rl) {
					if (rl.showList && rl.table == "sys_attachment") {
						return rl;
					}
				}).length;
		}
	}

	// STRY0135701 - all related lists are in one array.  Need to count for case where no related lists are shown, but additional lists are
	var baseTabIndex = 0;
	if(c.data.hideRelatedLists && $scope.hasAdditionalLists){
		baseTabIndex = c.data.f._related_lists.length - c.data.additionalLists.length;
	}

	$scope.countDocumentTabs = 0;
	if(c.data._docint_widget && c.data._docint_widget._docint_tabs){
		$scope.countDocumentTabs = c.data._docint_widget._docint_tabs.length;
	}

	$scope.submitting = false;
	$scope.mandatory = [];
	$scope.errorMessages = [];
	$scope.data.show_sql = false;
	$scope.saveButtonSuffix = spUtil.getAccelerator('s');
	$scope.isPageReady = false;
	$scope.adminMenu = {
		encodedPageUrl: encodeURIComponent($location.url()),
		getClientScriptCount: function() {
			var count = 0;
			if ($scope.data.f.client_script) {
				count += $scope.data.f.client_script.onChange.length;
				count += $scope.data.f.client_script.onLoad.length;
				count += $scope.data.f.client_script.onSubmit.length;
			}
			return count;
		}
	};

	// STRY0134743 - Out of Office Message on Task Request Form
	$scope.openRequestOOO = function(){
				var modalObject = {
                modalKey: 'TaskRequestOOO',
                title: c.data.TaskRequestOOOTitle, 
                message: '',
                backdrop: 'static',
                widget: 'tasker_modal_additional_information',
                widgetInput: {
                    table: 'x_153465_discovert_route_task_instance',
                    sys_id: c.data.f._fields.parent.value,
                    view: 'Task_Request_Responders', // NOTE, we may need to look up default
                    hideRelatedLists: true,
                    omitHeader: 'true',
                    hideAttachmentBtn: true,
                    isModal: true
                },
                shared: {},
                size: 'lg',
                buttons: [{
                            label: c.data.okButtonText,
                            cancel: true
                        }],
				footerStyle: {'display': 'block'}					
            };
		x_153465_discovert.twJS.openFormModal(spModal, modalObject);
	};
	$scope.getPanelBodyCss = function() {

		var panelBodyClassNames = '';

		// 2.8 | 2022-09-29 | mmcc | DFCT0011377 - Draft task with Subtasks, Subtask tab is not displaying any rows
		if (c.data.baseWidget == 'new_tasker_selection' && c.data.isModal == true) {
			panelBodyClassNames = 'dtech-overflow-auto';
		} else if (c.data.page_id == undefined && c.data.isModal == true || c.data.bifold ||
				(c.data.omitHeader == true && c.data.bifold == false && c.data.isModal == false)) {
			panelBodyClassNames = 'flex-column flex-grow dtech-overflow-hidden dtech-pad-all-0 dtech-pad-bottom-5';
		} else {
			panelBodyClassNames = '';
		}

		return panelBodyClassNames;
	};

	$scope.getPanelPanelCssByPageId = function() {

		var panelClassNames = '';

		// 2.8 | 2022-09-29 | mmcc | DFCT0011377 - Draft task with Subtasks, Subtask tab is not displaying any rows
		// 2.8 | 2022-09-28 | mmcc | DFCT0011375 - Add Subtask from New Draft Task fields are cut off; swap to if statement
		if (c.data.page_id == 'discovertasker_newtask') {
			if (c.data.isModal == false) {
				panelClassNames = 'dtech-topstick-posabso-rl-active dtech-w-100vw-40p flex-column flex-grow';
			} else {
				panelClassNames = 'dtech-topstick-posabso flex-column flex-grow';
			}
		} else if (c.data.baseWidget == 'new_tasker_selection' && c.data.isModal == true) {
			panelClassNames = 'dtech-topstick-posabso-rl-active dtech-w-100p flex-column flex-grow';
		} else if (c.data.page_id == undefined && c.data.isModal == true || c.data.bifold) {
			panelClassNames = 'dtech-topstick-posabso flex-column flex-grow';
		} else if (c.data.omitHeader == true && c.data.bifold == false && c.data.isModal == false) {
			panelClassNames = 'dtech-topstick-posabso-l-r-t-10 flex-column flex-grow';
		} else {
			panelClassNames = '';
		}

		return panelClassNames;
	};

	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs flexing; set the tab-content CSS class by Page ID
	$scope.getTabContentCssByPageId = function() {

		var tabContentClassNames = '';

		// 2.8 | 2022-08-25 | mmcc | DFCT0011206 - DocIntegrator needs to flex when used in the Tasker App; make it work in a modal
		// DFCT0011232
		if (c.data.page_id == undefined && c.data.isModal == true || c.data.bifold ||
				(c.data.omitHeader == true && c.data.bifold == false && c.data.isModal == false)) {
			tabContentClassNames = 'flex-column flex-grow dtech-overflow-hidden';
		} else {
			tabContentClassNames = '';
		}

		return tabContentClassNames;
	};

	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs flexing; set the tab-pane CSS class by Page ID
	$scope.getInfoTabPaneCssByPageId = function(tabName, index) {

		var tabPaneClassNames = '';

		// 2.8 | 2022-08-25 | mmcc | DFCT0011206 - DocIntegrator needs to flex when used in the Tasker App; make it work in a modal
		// DFCT0011232
		if (c.data.page_id == undefined && c.data.isModal == true || c.data.bifold || 
				(c.data.omitHeader == true && c.data.bifold == false && c.data.isModal == false)) {
			tabPaneClassNames = 'dtech-overflow-auto-pad-right-15-gutter-stable dtech-pad-left-5 dtech-pad-top-15';
		} else {
			tabPaneClassNames = 'dtech-pad-top-15';
		}

		if ($scope.isActiveTab(tabName, index)) {
			tabPaneClassNames += ' active';
		}

		return tabPaneClassNames;
	};

	// 2.8 | 2022-08-25 | mmcc | DFCT0011206 - DocIntegrator needs to flex when used in the Tasker App
	$scope.getTabPaneCssByBifoldModal = function(tabName, index) {

		var tabPaneClassNames = '';		

		if ($scope.isActiveTab(tabName, index)) {
			if (c.data.bifold || c.data.isModal) {
				tabPaneClassNames = ' dtech-force-column-grow active';
			} else {
				tabPaneClassNames += ' active';
			}
		}

		return tabPaneClassNames;
	};

	// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
	var watcher;

	// DFCT0010894, DFCT0010897, DFCT0010896, DFCT0010895, DFCT0010770
	if(c.data.sys_id && c.data.sys_id != -1){
		initRecordWatcher(c.data.table, "sys_id=" + c.data.sys_id);
	}
	function initRecordWatcher(table, filter) {
		if (watcher)
			watcher.unsubscribe();

		if (table && filter) {
			// STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
			var params = {};
			var watcherChannel = amb.getChannelRW(table, filter);
			amb.connect();
			watcher = watcherChannel.subscribe(function(name) {
				if (name.data.operation == 'delete') {
					if (c.data.parent_id) {
						c.data.sys_id = c.data.parent_id;
					} else {
						// DFCT0011088
						if(c.data.table=="x_153465_discovert_discover_routing_template" ||
							c.data.table=="x_153465_discovert_route_tasks"){
							$window.location.href = '../' + $scope.portal.url_suffix + 
								"?id=discovertasker_processtemplatelist&table=x_153465_discovert_discover_routing_template";
						// DFCT0011431
						} else if(c.data.table=="x_153465_discovert_discover_office_members"){
							// no need to respond here, window will close when member is deleted
							// member is only deleted in modal
						} else {
							// STRY0113838
							$window.location.href = '../' + $scope.portal.url_suffix;
						}
					}

				}

				$scope.server.update().then(function(){
					var parms =  {table: c.data.table, sys_id: c.data.sys_id, view: c.data.view};
					// DFCT0011036 - not sure why this was being raised here
					// $rootScope.$broadcast('$taskerTabbedForm.drillDownList.click', parms);
					$location.search('table', parms.table).search('sys_id', parms.sys_id).search('spa', '1');
					// DFCT0010343 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
					afterLoadFormReturns();
				});
			});
		}
	}	
	afterLoadFormReturns();

	// STRY0069986- RJ - Cert Push - Template DocInt Fix
	// STRY0119587
	function loadDocIntWidgets() {
		// STRY0086644 - added check for DocId not provided
		// DFCT0010857 - when doc int was off because the widget wasn't loaded on the sever.
		//               added a check to make sure docInt is loaded
		if (!c.data.hideDocuments && c.data.DocIntON &&
				(c.data.sys_id && c.data.sys_id !=-1 && c.data.sys_id !='') &&
				(c.data.table == 'x_153465_discovert_route_task_instance' ||
					c.data.table == 'x_153465_discovert_discover_routing_template' ||
					c.data.table == 'x_153465_discovert_route_tasks')) {
			loadDynamicDocIntWidgets();	
		}


	}
	//STRY0042748 | DI Integration: Tab Count for DocIntegrator List View provided
	//STRY0059178 | Shared Documents Folder  YOU ARE HERE!  nEED TO FIGURE OUT HOW TO ADD ANOTHER TAB.  ALSO NEED TO FIGURE OUT HOW TO GET THE DOCUMENT COUNT BELOW

	// RAJ - NOTE: - I put all of the DocInt code in one place so it is easy to find
	// We need to think about IF the counts could be in a DocInt Widget that adds multiple Tabs.
	// I am not sure that this can be done, but, if possible, we could drop the tab header as one javascript loaded file with this in it or some other way
	// IF this could be hidden in the DocInt widget, it would make it easier to add on widgets
	// the config should definitely be hidden in a DocInt widget that is added as one of the list of widgets only when admin
	// *******************************************************************************************************************************************************
	// for now, copy everything in this code block into widgets that want to use DocInt
	// *******************************************************************************************************************************************************
	//extension
	//This runs at first load.
	function loadDynamicDocIntWidgets() {
		if($scope.data._docint_widget){
			for (var i in $scope.data._docint_widget._docint_tabs) {
				var _tab = $scope.data._docint_widget._docint_tabs[i];

				// only clear the tab if it isn't the default empty tab
				if((c.data.DocIntShareFolderON || $scope.data._docint_widget._docint_tabs[i].caption != 'Shared Documents') ){
					loadDocIntWidget($scope.data._docint_widget._docint_tabs[i]);
				}
			}			
		}
	}

	function loadDocIntWidget(tab) {
		var widget_name = tab.widget_name;
		var widget_parameters = tab.widgetParameter;

		// 2.8 | 2022-08-25 | mmcc | DFCT0011206 - DocIntegrator needs to flex when used in the Tasker App; set isDocIntFlexboxUsed true when isModal=true
		var isDocIntFlexboxUsed = false;
		if (c.data.isModal) {
			isDocIntFlexboxUsed = true;
		} else {
			isDocIntFlexboxUsed = c.data.isFlexboxUsed;
		}


		if(widget_name == 'docint-list-items') {
			widget_parameters = {
				vw: tab.config["docintegrator_view-refValue"],
				mapRowSysId: c.data.sys_id + "",
				// deprecated readonly_flag
				//readonly_flag: !c.data.isActive,
				lw_name: tab.id + tab.caption,
				window_size: 20,
				config_sys_id: tab.id,
				// 2.8 | 2022-08-25 | mmcc | DFCT0011206 - DocIntegrator needs to flex when used in the Tasker App; add isDocIntFlexboxUsed
				isFlexboxUsed: isDocIntFlexboxUsed,
				// STRY0115311
				siblings : tab.siblings
			};
			// STRY0111049 - moved outside the IF statement and also set to use widgetname 
			spUtil.get(widget_name, widget_parameters).then(function(response) {
				tab.widget = response;
			});
		}

	}

	// STRY0120403 if filter changed, then record count will change and we will need to receive an updated count
	$scope.$on("discovertasker-widget-data-table-update_count", function (event, e) {
		if (e && e.title) {
			for (var i in $scope.data.f._related_lists) {
				var rl = $scope.data.f._related_lists[i];
				if(e.title == rl.title && rl.count != e.count){
					rl.count = e.count;
				}
			}
		}
	});

	//extension
	//This runs at first load.
	$scope.$on("docint.update_count", function (event, e) {
		// STRY0119587
		if (!c.data.hideDocuments ){
			if (e && e.source) {
				if($scope.data._docint_widget){
					for (var i in $scope.data._docint_widget._docint_tabs) {
						//
						var _section = $scope.data._docint_widget._docint_tabs[i];
						if (e.source == _section.id + _section.caption) {
							if (e.count) {
								_section.count = e.count;
							}
							if (e.errorMessages) {
								_section.error = e.errorMessages;
							}
							break;
						}
					}
				}
			}
		}
	});

	$scope.openDurationModal = function(){
		// call common duration modal
		var title = c.data.durationTitle + ': ' + c.data.f.title;
		x_153465_discovert.twJS.openDurationModal(spModal, title, c.data.table, c.data.sys_id);
	};
	$scope.openAssignmentModal = function(obj) {
		var title= c.data.assignmentTitle + ': ' + c.data.f.title;
		x_153465_discovert.twJS.openAssignmentModal(spModal, title, c.data.table, c.data.sys_id);
	};
	$scope.openOperationalModal = function(obj) {
		var title= c.data.operationalTitle + ': ' + c.data.f.title;
		x_153465_discovert.twJS.openOperationalModal(spModal, title, c.data.table, c.data.sys_id);
	};		
	// STRY0109208 - Add Create Icon
	$scope.openCreateModal = function() {
		var title= c.data.createTaskTitle + ': ' + c.data.f.title;
		var query = 'parent=' + c.data.sys_id;
		// DFCT0011271
		x_153465_discovert.twJS.openCreateModal(spModal, title, c.data.table, c.data.view, query, c.data.u_servicenow_form_view);
	};

	// DFCT0011353	- Template was opening new task
	$scope.openCreateSubTemplateTaskModal = function() {
		var modalObject = {
                modalKey: 'createTaskTemplateForm',
                title: c.data.addSubTaskTitle + ': ' + c.data.f.title, 
                message: '',
                backdrop: 'static',
                widget: 'discovertasker-formtab',
                widgetInput: {
                    table: 'x_153465_discovert_route_tasks',
                    query: 'parent=' + c.data.sys_id,
                    sys_id: -1,
                    view: 'Default_View', // NOTE, we may need to look up default
                    hideRelatedLists: true,
                    omitHeader: 'true',
                    hideAttachmentBtn: true,
                    isModal: true
                },
                shared: {},
                size: 'lg',
                buttons: []
            };
		x_153465_discovert.twJS.openFormModal(spModal, modalObject);
	};
	// 2.8 | 2022-04-14 | mmcc | STRY0119578 - Existing Task Form- Remove DTLV icon and Task Tree View icon
	//$scope.openTreeViewModal = function(obj) {
	//	x_153465_discovert.twJS.openTreeViewModal(spModal, c.data.sys_id);
