			if(data.sys_id == -1 || rec.state == -6){
				// for new items data.view will be set on the input for a modal, and on the url for a full page new item
				view = data.view || (input || {}).view || (options || {}).view || $sp.getParameter("view");
				// DFCT0011092 - Mobile - New Task form does NOT display on the Mobile 
				// load the default tasker form view
				taskFormView = oUserPref.getDefaultTaskerFormView(null);
			} else {
				// STRY0119580
				taskFormView = oUserPref.getDefaultTaskerFormView(rec);
			}
			// DFCT0011092 - Mobile - New Task form does NOT display on the Mobile 
			if(taskFormView){
				data.taskFormView = taskFormView;
			}			

			url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(data.sys_id, view);
			data.view = url_Properties.view;
		}

	} else {
		data.view = data.view || $sp.getParameter("view") || "sp"; // SP default
	}
	// STRY0113838
	data.url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(data.sys_id,data.view);

