// 2.8.1 | 2023-03-15 | mmcc | STRY0136499 - 2.8.1 Set CSS Style for Classification based on Value; end commented out blocked

	// 2.8.1 | 2023-03-15 | mmcc | STRY0136499 - 2.8.1 Set CSS Style for Classification based on Value; new version
	if (data.table == "x_153465_discovert_route_task_instance") {
		if (data.sys_id == -1) {
			if (data.f._fields.parent) {
				var parentID = data.f._fields.parent.value;
				var parentRec = new GlideRecord("x_153465_discovert_route_task_instance");
				if (parentRec.get(parentID)) {
					if (parentRec.getDisplayValue("classification") != undefined) {
						data.classification = parentRec.getDisplayValue("classification");
						data.classificationValue = parentRec.getValue("classification");
						// Force object to a string
						data.classificationValue2 = "" + parentRec.classification;

					}

					if (parentRec.getDisplayValue("assignment_group") != undefined) {
						data.restrictedGroup = parentRec.getDisplayValue("assignment_group");
					}
				}
			}
		} else {
			if (data.f._fields.number) {
				data.number = data.f._fields.number.displayValue;
			}

			// STRY0051139
			data.task_name = rec.task_name; //data.number + ": " + data.f._fields['short_description']["displayValue"];
			data.f.task_instance__state = '';

			data.classification = rec.getDisplayValue("classification");
