	// DFCT0011062 need to process related lists to show documents if documents are not hidden
	if(data.sys_id!=-1 && (!data.hideRelatedLists || !data.hideDocuments)){
		// DFCT0011678 - make this an empty array if new item
		allTabs = data.f._related_lists;
		var rlParams =	{
			// STRY0120159 
			task_id: data.task_id,
			// DFCT0011271
			u_servicenow_form_view: data.u_servicenow_form_view,
			hideTaskFilter: data.hideTaskFilter,
			showStatesMultipleBar: true,
			arrRelatedLists: options.relatedLists_to_include, 
			f_related_lists: data.f._related_lists,
			rec: rec, 
			table: data.table,
			canCreateSubTask: data.canCreateSubTask, 
			emailEnabled: data.emailEnabled,
			hideDocuments: data.hideDocuments,
			// DFCT0011062 improves efficiency of what is loaded to HTML
			hideRelatedLists: data.hideRelatedLists,
			page_id: data.page_id,
			view: data.view, 
			isModal: data.isModal,
			// 2.8 | 2022-08-19 | mmcc | DFCT0011084 - Page Tree Bi-Fold needs to match the standard layout for flexing header-body-footer; add bifold
			bifold: data.bifold,
			sharedAttachSys_ID: data.sharedAttachSys_ID,
			sharedAttachTableName: data.sharedAttachTableName,
			attachmentSharedFolderON: data.AttachmentSharedFolderON, 
			myAttachSys_ID: myAttachSys_ID,
			attachmentsON: data.SNAttachmentsON,
			// DFCT0011217
			canAttach: data.canAttach
		};	

		// STRY0135701 - Subtask; Detailed Status; Action Log; and Final Response tabs
		allTabs = taskData.loadRelatedLists(rlParams);

	}

	// STRY0135701 - Subtask; Detailed Status; Action Log; and Final Response tabs
	if(data.additionalLists){
		// 2.8.5 | 2023-07-24 | mmcc | STRY0135715 - Edit privilege for my comments in the All Responses Modal; added responseEditorControl
		allTabs = taskData.loadAdditionalLists(data.additionalLists, allTabs, rec, data.u_servicenow_form_view, 
											data.isModal, data.bifold, data.task_id, data.responseEditorControl);
	}
	// STRY0122687 - count tabs
	data.f._related_lists = allTabs;
